    if (pattern.size() != words.size()) return false;

    unordered_map<char, string> charToWord;
    unordered_map<string, char> wordToChar;

    for (int i = 0; i < pattern.size(); i++)
    {
        char c = pattern[i];
        string w = words[i];

        if (charToWord.count(c) && charToWord[c] != w) return false;
        if (wordToChar.count(w) && wordToChar[w] != c) return false;

        charToWord[c] = w;
        wordToChar[w] = c;
    }

    return true;
}

int main()
{
    cout << (wordPattern("abba", "dog cat cat dog") ? "true" : "false") << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>

using namespace std;

vector<vector<string>> groupAnagrams(vector<string> &strs)
{
    vector<vector<string>> groups;

    for (string &s : strs)
    {
        string sorted = s;
        sort(sorted.begin(), sorted.end());

        bool placed = false;
        for (auto &group : groups)
        {
            string groupSorted = group[0];
            sort(groupSorted.begin(), groupSorted.end());
            if (groupSorted == sorted)
            {
                group.push_back(s);
                placed = true;
                break;
            }
        }

        if (!placed) groups.push_back({s});
    }

    return groups;
}

int main()
{
    vector<string> strs = {"eat", "tea", "tan", "ate", "nat", "bat"};

    auto groups = groupAnagrams(strs);
    cout << groups.size() << endl;

    return 0;
}

#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <unordered_map>

using namespace std;

vector<vector<string>> groupAnagrams(vector<string> &strs)
{
    unordered_map<string, vector<string>> groups;

    for (string &s : strs)
    {
        string key = s;
        sort(key.begin(), key.end());
        groups[key].push_back(s);
    }

    vector<vector<string>> result;
    for (auto &[key, group] : groups) result.push_back(group);

    return result;
}

int main()
{
    vector<string> strs = {"eat", "tea", "tan", "ate", "nat", "bat"};

    auto groups = groupAnagrams(strs);
    cout << groups.size() << endl;

    return 0;
}

